package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"

	"github.com/gorilla/mux"
	"github.com/html/template"
)

type Comment struct {
	ID    string `json:"id"`
	Text  string `json:"text"`
	Author string `json:"author"`
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	id := vars["id"]

	comments := []Comment{
		{ID: "1", Text: "<b>Hello</b> world!", Author: "John"},
		{ID: "2", Text: "This is a <i>test</i>", Author: "Jane"},
	}

	tmpl, err := template.ParseFiles("templates/comments.html")
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	err = tmpl.ExecuteTemplate(w, "comments.html", comments)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
	}
}

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/users/{id}/comments", commentsHandler).Methods("GET")

	fmt.Println("Server is running on port 8000")
	log.Fatal(http.ListenAndServe(":8000", r))
}